test_cases.post_script:
pm.test('TC01 健康检查通过', () => {
    pm.response.to.have.status(200);
    const body = pm.response.json();
    pm.expect(body.status).to.equal('healthy');
    console.log('✅ TC01 通过 - 后端服务健康');
});

pm.test('TC02 登录成功', () => {
    pm.response.to.have.status(200);
    const body = pm.response.json();
    pm.expect(body).to.have.property('access_token');
    // 写入环境变量供后续 TC 使用
    pm.environment.set('token', body.access_token);
    console.log('✅ TC02 通过 - Token 已写入环境变量');
});

pm.test('TC03 模型列表正常', () => {
    pm.response.to.have.status(200);
    const body = pm.response.json();
    pm.expect(body.models).to.be.an('array').with.length.greaterThan(0);
    const availableModels = body.models.filter(m => m.available);
    console.log('✅ TC03 通过 - 共', body.models.length, '个模型，', availableModels.length, '个可用');
});

pm.test('TC04 知识库列表接口正常', () => {
    pm.response.to.have.status(200);
    const body = pm.response.json();
    pm.expect(body).to.be.an('array');
    if (body.length > 0) {
        pm.environment.set('test_kb_id', body[0].id);
        console.log('✅ TC04 通过 - 共', body.length, '个知识库，首个 KB ID:', body[0].id);
    } else {
        console.log('✅ TC04 通过 - 当前无知识库（首次使用时正常）');
    }
});

pm.test('TC05 知识广场接口正常', () => {
    pm.response.to.have.status(200);
    const body = pm.response.json();
    pm.expect(body).to.be.an('array');
    console.log('✅ TC05 通过 - 广场共', body.length, '条数据（最多返回5条）');
});

pm.test('TC06 用户信息接口正常', () => {
    pm.response.to.have.status(200);
    const body = pm.response.json();
    pm.expect(body).to.have.property('email');
    console.log('✅ TC06 通过 - 当前用户:', body.email);
});

pm.test('TC07 审计日志接口正常', () => {
    pm.response.to.have.status(200);
    console.log('✅ TC07 通过 - 审计日志接口响应正常');
    console.log('\n🎉 冒烟测试全部通过！后端服务健康。');
});
